/**
 * 纯 UI 组件，不包含业务逻辑，单纯为了优化这里的性能
 */
import { Divider } from 'antd'
import { Fragment } from 'react'

import type { TooltipProps } from 'antd'

import MoreButton from './_components/MoreButton'
import OptionButton from './_components/OptionButton'
import OptionDropdown from './_components/OptionDropdown'
import OptionIcon from './_components/OptionIcon'

import type { IImageMenuOptionsProps, IMenuCoreOptionsProps } from '.'
import type { MenuOption, TMenuOptionKey } from './_types'

interface IPureMenuOptionUIProps {
  className?: IMenuCoreOptionsProps['className']
  menuDropdownOpen: boolean
  tooltipOpen: boolean
  openClassName?: IMenuCoreOptionsProps['openClassName']
  onClick?: IMenuCoreOptionsProps['onClick']
  expand?: IImageMenuOptionsProps['expand']
  onlyExpand?: IMenuCoreOptionsProps['onlyExpand']
  iconOnly?: IMenuCoreOptionsProps['iconOnly']
  flattenMore?: IMenuCoreOptionsProps['flattenMore']
  iconClassName?: IMenuCoreOptionsProps['iconClassName']
  optionClassName?: IMenuCoreOptionsProps['optionClassName']
  align?: IMenuCoreOptionsProps['align']
  optionOpenClassName?: IMenuCoreOptionsProps['optionOpenClassName']
  menuDropdownOpenKey: TMenuOptionKey
  dropdownOptions: MenuOption[]
  handleAfterOpenChange: (open: boolean, key: TMenuOptionKey) => void
  setTooltipOpen: (value: React.SetStateAction<boolean>) => void
  options: MenuOption[]
  modalComponent: JSX.Element
}

const PureMenuOptionUI = (props: IPureMenuOptionUIProps) => {
  const {
    className,
    menuDropdownOpen,
    tooltipOpen,
    openClassName,
    onClick,
    expand,
    onlyExpand,
    iconOnly,
    flattenMore,
    iconClassName,
    optionClassName,
    align,
    optionOpenClassName,
    menuDropdownOpenKey,
    dropdownOptions,
    handleAfterOpenChange,
    setTooltipOpen,
    options,
    modalComponent,
  } = props

  const renderOption = (target: MenuOption) => {
    const button = iconOnly ? (
      <OptionIcon
        {...target}
        tooltipProps={{
          ...target.tooltipProps,
          onOpenChange: (open) => {
            setTooltipOpen(open)
            ;(target.tooltipProps as TooltipProps)?.onOpenChange?.(open)
          },
        }}
        iconClassName={tw`${iconClassName} ${target.iconClassName}`}
        className={tw`
          ${optionClassName}
          ${target.className}
          ${menuDropdownOpen && menuDropdownOpenKey === target.key ? optionOpenClassName : ''}
        `}
      />
    ) : (
      <OptionButton
        {...target}
        tooltipProps={{
          ...target.tooltipProps,
        }}
        className={tw`
          ${optionClassName}
          ${menuDropdownOpen && menuDropdownOpenKey === target.key ? optionOpenClassName : ''}
        `}
      />
    )

    if (target.children && !target.disabled) {
      return (
        <OptionDropdown
          key={target.key}
          items={target.children}
          placement={target.placement}
          align={{
            ...align,
            ...target.tooltipProps?.align,
          }}
          afterOpenChange={(open) => {
            handleAfterOpenChange(open, target.key as TMenuOptionKey)
          }}
        >
          {button}
        </OptionDropdown>
      )
    }

    return button
  }

  const renderFlattenMore = () => {
    if (onlyExpand || !dropdownOptions.length) return null
    return dropdownOptions.map((target) => {
      return (
        <Fragment key={`more-inline-${target.key}`}>
          {renderOption(target)}
        </Fragment>
      )
    })
  }

  return (
    <>
      <div
        className={tw`
          flex flex-wrap items-center gap-2 gap-x-1.5
          ${className}
          ${menuDropdownOpen || tooltipOpen ? openClassName : ''}
        `}
        onClick={onClick}
      >
        {expand?.map((expandKey, index) => {
          if (expandKey === 'more')
            return flattenMore ? (
              <Fragment
                // eslint-disable-next-line react/no-array-index-key
                key={`${expandKey}-${index}`}
              >
                {renderFlattenMore()}
              </Fragment>
            ) : (
              <MoreButton
                // eslint-disable-next-line react/no-array-index-key
                key={`${expandKey}-${index}`}
                onlyExpand={onlyExpand}
                iconOnly={iconOnly}
                align={align}
                iconClassName={iconClassName}
                optionClassName={optionClassName}
                optionOpenClassName={optionOpenClassName}
                menuDropdownOpen={menuDropdownOpen}
                menuDropdownOpenKey={menuDropdownOpenKey}
                dropdownOptions={dropdownOptions}
                handleAfterOpenChange={handleAfterOpenChange}
              />
            )
          if (expandKey === 'divider')
            return (
              <Divider
                type='vertical'
                className='mx-0 h-3'
                // eslint-disable-next-line react/no-array-index-key
                key={`${expandKey}-${index}`}
              />
            )

          const target = options.find((item) => item.key === expandKey)

          if (!target) {
            return null
          }

          return renderOption(target)
        })}

        {!expand?.includes('more') && (
          <>
            {flattenMore ? (
              renderFlattenMore()
            ) : (
              <MoreButton
                onlyExpand={onlyExpand}
                iconOnly={iconOnly}
                align={align}
                iconClassName={iconClassName}
                optionClassName={optionClassName}
                optionOpenClassName={optionOpenClassName}
                menuDropdownOpen={menuDropdownOpen}
                menuDropdownOpenKey={menuDropdownOpenKey}
                dropdownOptions={dropdownOptions}
                handleAfterOpenChange={handleAfterOpenChange}
              />
            )}
          </>
        )}
      </div>
      {modalComponent}
    </>
  )
}

export default memo(PureMenuOptionUI)

import { Trans } from '@lingui/react/macro'
import { useHover } from 'ahooks'
import { Button, type ButtonProps } from 'antd'

import { useButtonState } from '../../_hooks/useButtonState'
import IconWithTooltip from '../IconWithTooltip'
import UpgradeIcon from '../UpgradeIcon'

import type { MenuOption } from '../../_types'

const OptionButton = (
  props: Omit<ButtonProps, 'children' | 'onClick'> & MenuOption,
) => {
  const {
    className,
    premium,
    iconOnly,
    icon: _icon,
    label: _label,
    onClick,
    onTrack,
    tooltipProps,
    showTooltip,
    comingSoon,
    ...restProps
  } = props
  const ref = useRef<HTMLButtonElement>(null)
  const isHovering = useHover(ref)

  const { icon, label, tooltipTitle, setState } = useButtonState({
    icon: _icon,
    label: _label,
    tooltipTitle: tooltipProps?.title,
  })

  return (
    <IconWithTooltip
      tooltipProps={{ ...tooltipProps, title: tooltipTitle }}
      showTooltip={showTooltip && !!tooltipTitle}
    >
      <Button
        ref={ref}
        className={tw`!bg-f-bg-layout text-f-text-tertiary flex h-7 items-center gap-x-1 !border-none !px-2 text-sm ${className}`}
        icon={
          comingSoon && isHovering ? null : (
            <CssIcon className={cls`${icon} size-4`} />
          )
        }
        onClick={(e) => {
          onTrack?.(e.currentTarget)
          onClick?.({ ...setState, domEvent: e })
        }}
        {...restProps}
      >
        <div className={cls`flex w-full items-center gap-x-1`}>
          {!iconOnly &&
            (comingSoon && isHovering ? (
              <span>
                <Trans>Coming Soon</Trans>
              </span>
            ) : (
              <span>{label}</span>
            ))}
          {premium && <UpgradeIcon />}
        </div>
      </Button>
    </IconWithTooltip>
  )
}

export default OptionButton

content.text:
现在看清楚了。这里**确实有性能隐患**。

## 问题分析

`<OptionButton {...target} />` 中，`target` 是一个 `MenuOption` 对象，看看它包含什么：

```tsx
// MenuOption 的字段（合并后约 20+ 个）
{
  key, label, icon, onClick, onTrack, premium,
  children, tooltipProps, disabled, loading,
  comingSoon, className, iconClassName, placement,
  showTooltip, iconOnly, onSuccess, onFavoriteSuccess,
  sourceType, onCreate, ...
}
```

而 OptionButton 的签名是：

```tsx
// Omit<ButtonProps, 'children' | 'onClick'> & MenuOption
const OptionButton = (props) => {
  const { className, premium, iconOnly, icon, label, onClick, onTrack,
          tooltipProps, showTooltip, comingSoon,
          ...restProps  // ← 剩余全部透传给 antd Button
  } = props
```

**问题在 `{...restProps}`（第 53 行）**：`MenuOption` 中大量业务字段（`onSuccess`、`onFavoriteSuccess`、`sourceType`、`onCreate`、`children` 等）会通过 `restProps` 透传到 antd `<Button>` 的 DOM 上，导致：

1. **React 控制台警告**：非标准 HTML 属性被渲染到 DOM
2. **DOM 污染**：`<button onsuccess="..." sourcetype="...">` 这些无意义属性出现在 HTML 中
3. **性能不是主要问题**，但设计上不干净

## 关于渲染性能

`{...target}` spread 一个对象 → **不会直接导致额外重渲染**。

但这里有一个间接问题：`target` 来自 `options.find()`，而 `options` 数组如果每次父组件渲染时重新构建，里面的 `onClick`、`onSuccess` 等函数都是新引用。即使 OptionButton 用了 `memo`，浅比较也会判定 props 变了。

不过 OptionButton **没有用 `memo`**，所以 spread 不 spread 对渲染没区别——父组件一渲染它就渲染。

## 真正的问题：restProps 泄漏到 DOM

```tsx
// OptionButton 第 53 行
<Button {...restProps}>
// restProps 包含了 onSuccess, onFavoriteSuccess, sourceType, onCreate 等
// 这些全部会被 antd Button 转发到 <button> DOM 元素上
```

## 更合理的写法

**明确 pick 需要的字段，而非 spread 整个对象**：

```tsx
// OptionButton 应该只取自己需要的
const OptionButton = (props: MenuOption) => {
  const {
    className, premium, iconOnly, icon, label,
    onClick, onTrack, tooltipProps, showTooltip,
    comingSoon, disabled, loading,
  } = props
  // 不再 ...restProps

  return (
    <IconWithTooltip ...>
      <Button
        disabled={disabled}
        loading={loading}
        className={...}
        icon={...}
        onClick={...}
      >
        ...
      </Button>
    </IconWithTooltip>
  )
}
```

## 总结

| 问题 | 严重程度 | 说明 |
|------|---------|------|
| `{...target}` 导致重渲染？ | 低 | OptionButton 没有 memo，spread 不影响 |
| `{...restProps}` 泄漏到 DOM | 中 | 业务字段污染 HTML，会有 React 警告 |
| 设计解耦合理吗？ | 合理 | `MenuOption` 作为统一数据结构，spread 传入可以减少模板代码 |
| 最佳实践 | — | 组件内部**显式解构**需要的字段，不要 `...rest` 透传给 DOM 组件 |

一句话：**`{...target}` 传入自定义组件没问题，问题出在 OptionButton 内部又 `{...restProps}` 给了 antd Button（最终到 DOM）**。

